import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"新興航運（2605）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/航運產業/02_台灣上市航運股/2605_新興.md","filePath":"Deep32Q知識庫/產業洞察/航運產業/02_台灣上市航運股/2605_新興.md"}'),i={name:"Deep32Q知識庫/產業洞察/航運產業/02_台灣上市航運股/2605_新興.md"};function o(n,t,s,d,h,c){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="新興航運-2605" tabindex="-1">新興航運（2605） <a class="header-anchor" href="#新興航運-2605" aria-label="Permalink to &quot;新興航運（2605）&quot;">​</a></h1><h2 id="📊-基本資料" tabindex="-1">📊 基本資料 <a class="header-anchor" href="#📊-基本資料" aria-label="Permalink to &quot;📊 基本資料&quot;">​</a></h2><ul><li><strong>股票代號</strong>：2605.TW</li><li><strong>定位</strong>：散裝+油輪雙軌營運</li></ul><h2 id="💰-2025年財務數據" tabindex="-1">💰 2025年財務數據 <a class="header-anchor" href="#💰-2025年財務數據" aria-label="Permalink to &quot;💰 2025年財務數據&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>數值</th><th>同比變化</th></tr></thead><tbody><tr><td>全年合併營收</td><td>新台幣44.08億元</td><td>—</td></tr><tr><td>稅後純益</td><td>新台幣8.47億元</td><td>—</td></tr><tr><td>EPS</td><td>新台幣1.45元</td><td>—</td></tr></tbody></table><p><strong>Q4 2025單季：</strong></p><ul><li>稅後純益：5.62億元（受惠航運市場回溫及運價走揚）</li><li>EPS：0.96元</li></ul><blockquote><p>註：董事會決議擬配發每股現金股利1元。 來源：chinatimes.com、ettoday.net</p></blockquote><h2 id="🚢-船隊結構-自有及控制" tabindex="-1">🚢 船隊結構（自有及控制） <a class="header-anchor" href="#🚢-船隊結構-自有及控制" aria-label="Permalink to &quot;🚢 船隊結構（自有及控制）&quot;">​</a></h2><ul><li><strong>總載重噸位</strong>：約280萬載重噸</li><li><strong>散裝船</strong>：4艘卡姆薩型、7艘海岬型、1艘超大型礦砂船（VLOC）</li><li><strong>油輪</strong>：3艘超大型油輪（VLCC）</li></ul><p><strong>船型營運表現：</strong></p><ul><li>VLCC在2025年Q4是最賺錢的船型，平均日租金達7.02萬美元</li><li>散裝市場：BDI全年均數1681點（較前年減4%），Q4指數達2159點（年增47%）</li></ul><h2 id="📈-營運策略與市場展望" tabindex="-1">📈 營運策略與市場展望 <a class="header-anchor" href="#📈-營運策略與市場展望" aria-label="Permalink to &quot;📈 營運策略與市場展望&quot;">​</a></h2><ul><li><strong>核心策略</strong>：60%定期租約鎖定穩定現金流，40%現貨市場彈性掌握行情</li><li><strong>碳強度管理</strong>：積極投入CII管理，評估生質燃料、風力輔助、低摩擦塗料等技術方案</li><li><strong>法規應對</strong>：全面應對歐盟ETS與FuelEU Maritime法規</li><li><strong>油輪市場</strong>：2025年受伊朗/以色列緊張局勢、霍爾木茲海峽風險、俄羅斯制裁升級影響，VLCC和Suezmax租船費率維持高位</li><li><strong>散裝市場</strong>：全球運力供給吃緊，俄烏重建需求預期，BDI Q4大幅回升</li></ul><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>chinatimes.com (2026-03-13): 新興航運2025全年營收44.08億元、EPS 1.45元</li><li>ettoday.net: 新興航運Q4營運分析與船隊結構</li><li>uanalyze.com.tw: 新興航運散裝+油輪雙軌營運分析</li><li>xindemarinenews.com: 2025年油輪市場展望與VLCC日租金</li></ol>',16)])])}const g=a(i,[["render",o]]);export{_ as __pageData,g as default};
